import{_ as e,o as i,c as r,ah as p}from"./chunks/framework.C2p4DT9L.js";const _=JSON.parse('{"title":"微服务","description":"","frontmatter":{"title":"微服务","order":20},"headers":[],"relativePath":"server/distribute/micro/index.md","filePath":"server/distribute/micro/index.md"}'),l={name:"server/distribute/micro/index.md"};function t(n,a,d,s,o,h){return i(),r("div",null,[...a[0]||(a[0]=[p('<h1 id="微服务治理" tabindex="-1">微服务治理 <a class="header-anchor" href="#微服务治理" aria-label="Permalink to “微服务治理”">​</a></h1><p>微服务架构将单体应用拆分为多个小型服务，每个服务独立开发、部署、扩展。微服务治理是确保微服务架构可运行、可维护、可扩展的一套技术和实践。</p><p>微服务架构引入的核心理由是单数据库的 IO 瓶颈和压力，此外，引入微服务还有其他理由，单体应用的问题：代码库庞大、部署困难、技术栈固定、扩展受限、单点故障。</p><p>微服务的代价：分布式复杂性（服务间通信、数据一致性）、运维复杂度（大量服务需要管理）、调试困难（调用链路长）。</p><p>微服务治理的目标：管理服务数量庞大的系统，保证服务的可用性、性能、一致性。</p><h2 id="微服务治理的核心组件" tabindex="-1">微服务治理的核心组件 <a class="header-anchor" href="#微服务治理的核心组件" aria-label="Permalink to “微服务治理的核心组件”">​</a></h2><ul><li>服务注册与发现：服务如何注册自己的地址，客户端如何发现服务地址</li><li>配置中心：如何动态管理配置，所有实例能够及时获取最新配置</li></ul><p>其他组件：</p><ul><li>服务通信：服务间如何通信，同步调用还是异步消息</li><li>负载均衡：如何将请求分发到多个服务实例</li><li>熔断降级：服务故障时如何快速失败，避免雪崩</li><li>限流：如何保护服务不被过载请求打垮</li><li>链路追踪：如何追踪一个请求经过的所有服务</li><li>监控告警：如何监控服务的状态，及时发现问题</li></ul><h2 id="微服务拆分原则" tabindex="-1">微服务拆分原则 <a class="header-anchor" href="#微服务拆分原则" aria-label="Permalink to “微服务拆分原则”">​</a></h2><p>按业务能力拆分：订单服务、库存服务、用户服务。每个服务负责一个完整的业务能力。</p><p>按数据子域拆分：参考领域驱动设计（DDD），每个服务对应一个限界上下文。</p><p>单一职责：每个服务只做一件事，做好一件事。</p><p>独立数据存储：每个服务有自己的数据库，避免共享数据库。</p><p>无状态服务：服务不保存状态，状态存储在外部（Redis、数据库），便于扩展。</p><p>API 网关：统一入口，处理认证、限流、路由、聚合。</p><h2 id="微服务的数据一致性" tabindex="-1">微服务的数据一致性 <a class="header-anchor" href="#微服务的数据一致性" aria-label="Permalink to “微服务的数据一致性”">​</a></h2><p>分布式事务：跨服务的数据一致性难以保证，强一致性方案性能差。</p><p>最终一致性：接受短暂不一致，通过补偿机制保证最终一致。</p><p>幂等性：同一操作执行多次，结果与执行一次相同。</p><p>事件驱动：通过事件总线异步通信，降低服务耦合。</p><p>Saga 模式：长事务拆分为多个本地事务，每个事务有补偿。</p><p>TCC 模式：Try-Confirm-Cancel 三阶段提交。</p><h2 id="微服务的测试与部署" tabindex="-1">微服务的测试与部署 <a class="header-anchor" href="#微服务的测试与部署" aria-label="Permalink to “微服务的测试与部署”">​</a></h2><p>单元测试：测试单个服务的逻辑。</p><p>集成测试：测试服务间的交互。</p><p>契约测试：测试服务接口的兼容性。</p><p>金丝雀发布：先发布到少量实例，验证后全量发布。</p><p>蓝绿部署：维护两套环境，切换流量实现零停机部署。</p><p>滚动发布：逐个替换实例，保证持续可用。</p><p>微服务治理是微服务架构的基石，理解服务治理的组件和模式，有助于设计可维护的微服务系统。</p>',31)])])}const m=e(l,[["render",t]]);export{_ as __pageData,m as default};
